import { Component } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { environment } from '../../../../environments/environment';

@Component({
  selector: 'app-grade-entry',
  templateUrl: './grade-entry.component.html',
  styleUrls: ['./grade-entry.component.css']
})
export class GradeEntryComponent {
  grade = { studentId: null, subject: '', score: null, term: '' };
  message = '';
  constructor(private http: HttpClient) {}

  onSubmit() {
    this.http.post(`${environment.apiUrl}/grades`, this.grade).subscribe({
      next: () => this.message = 'Grade saved successfully!',
      error: () => this.message = 'Error saving grade.'
    });
  }
}
